import{_ as s,o as a,c as t,a2 as i}from"./chunks/framework.DZO5kRrk.js";const u=JSON.parse('{"title":"前端转 Flutter 笔记 (Day 1)：环境搭建与项目“大扫除”","description":"","frontmatter":{},"headers":[],"relativePath":"docs/flutter/day-01.md","filePath":"docs/flutter/day-01.md"}'),l={name:"docs/flutter/day-01.md"};function o(n,e,r,d,p,c){return a(),t("div",null,[...e[0]||(e[0]=[i(`<h1 id="前端转-flutter-笔记-day-1-环境搭建与项目-大扫除" tabindex="-1">前端转 Flutter 笔记 (Day 1)：环境搭建与项目“大扫除” <a class="header-anchor" href="#前端转-flutter-笔记-day-1-环境搭建与项目-大扫除" aria-label="Permalink to &quot;前端转 Flutter 笔记 (Day 1)：环境搭建与项目“大扫除”&quot;">​</a></h1><blockquote><p><strong>写在前面</strong>：作为一名 Vue 开发者，习惯了 <code>npm run dev</code> 的丝滑和 <code>Element Plus</code> 的便捷，初入 Flutter 可能会被那堆复杂的 Android/iOS 配置文件吓退。 其实，Flutter 的现代开发体验已经离前端非常近了。这是我（一个 Vue 老鸟）的 Flutter 学习日记第一天。</p></blockquote><h2 id="_1-工程结构-flutter-里的-package-json" tabindex="-1">1. 工程结构：Flutter 里的 package.json <a class="header-anchor" href="#_1-工程结构-flutter-里的-package-json" aria-label="Permalink to &quot;1. 工程结构：Flutter 里的 package.json&quot;">​</a></h2><p>创建完项目，第一眼看到的 <code>pubspec.yaml</code> 其实就是前端的 <code>package.json</code>。</p><ul><li><strong>依赖管理</strong>：<code>dependencies</code> 对应 <code>dependencies</code>，<code>dev_dependencies</code> 对应 <code>devDependencies</code>。</li><li><strong>区别</strong>：Flutter 对缩进极其严格（YAML 格式），少一个空格都会报错，这点比 JSON 严格。</li></ul><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">dependencies</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  flutter</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    sdk</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">flutter</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # 相当于 npm install flutter_screenutil</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  flutter_screenutil</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">^5.9.3</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> </span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # 相当于 npm install flutter_riverpod</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  flutter_riverpod</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">^2.5.1</span></span></code></pre></div><h2 id="_2-资源管理-告别手写路径-🙅‍♂️" tabindex="-1">2. 资源管理：告别手写路径 🙅‍♂️ <a class="header-anchor" href="#_2-资源管理-告别手写路径-🙅‍♂️" aria-label="Permalink to &quot;2. 资源管理：告别手写路径 🙅‍♂️&quot;">​</a></h2><p>在 Vue 里，我们可能习惯了 <code>src=&quot;@/assets/logo.png&quot;</code>。 但在 Flutter 原生开发中，如果要在代码里写字符串 <code>&quot;assets/images/logo.png&quot;</code>，一旦改文件名或拼错，运行起来才报错，非常痛苦。</p><p><strong>神器推荐：FlutterGen</strong> 这东西就像前端的自动导入插件。配置好后，运行脚本，它会自动扫描所有图片生成一个 <code>Assets</code> 类。</p><p><strong>对比体验：</strong></p><ul><li>🔴 <strong>Old</strong>: <code>Image.asset(&#39;assets/images/logo_blue.png&#39;)</code> (容易拼错)</li><li>🟢 <strong>New</strong>: <code>Assets.images.logoBlue.image()</code> (类型安全，有补全，甚至能预览！)</li></ul><p>这也是我进项目做的第一件事：写了一个 <code>gen.sh</code> 脚本，把生成命令封装起来，体验接近 <code>npm run build</code>。</p><h2 id="_3-路由去哈希-url-的洁癖-🧹" tabindex="-1">3. 路由去哈希：URL 的洁癖 🧹 <a class="header-anchor" href="#_3-路由去哈希-url-的洁癖-🧹" aria-label="Permalink to &quot;3. 路由去哈希：URL 的洁癖 🧹&quot;">​</a></h2><p>Flutter Web 默认的 URL 也是带 <code>#</code> 的 (Hash Mode)，像 <code>localhost:8080/#/login</code>。 对于有洁癖的前端来说，必须利用 <code>url_strategy</code> 把它改成 Path Mode (<code>localhost:8080/login</code>)。</p><p>虽然这次做的是 App，但在调试阶段（或未来发 Web 版）看着干净的 URL 心情都会好很多。</p><h2 id="_4-调试神器-vs-code-配置" tabindex="-1">4. 调试神器：VS Code 配置 <a class="header-anchor" href="#_4-调试神器-vs-code-配置" aria-label="Permalink to &quot;4. 调试神器：VS Code 配置&quot;">​</a></h2><p>Flutter 的调试体验其实优于 Web。在 <code>.vscode/launch.json</code> 里配置好设备后，<strong>F5 一键启动</strong>。 最爽的是 <strong>Hot Reload (热重载)</strong>，按一下 <code>r</code>，界面状态保留，UI 瞬间刷新。这比 Webpack HMR 有时还要快和稳。</p><h2 id="day-1-总结" tabindex="-1">Day 1 总结 <a class="header-anchor" href="#day-1-总结" aria-label="Permalink to &quot;Day 1 总结&quot;">​</a></h2><p>第一天没有急着画页面，而是：</p><ol><li><strong>统一规范</strong>：清理了官方 Demo 的计数器代码。</li><li><strong>配置工具</strong>：搞定了自动生成资源的脚本。</li><li><strong>启动屏</strong>：做了一个包含 Logo 的 Splash Page，作为 App 的门面。</li></ol><p><strong>感悟</strong>：Flutter 的工程化程度很高，只要配置好基建，后面的开发效率不输 Vue。明天开始挑战 UI 布局！</p>`,21)])])}const g=s(l,[["render",o]]);export{u as __pageData,g as default};
